solution: class Solution {
public:
    int numSub(string s) {
        const int MOD = 1'000'000'007;
        long long res = 0;
        long long cur = 0;
        for (char c : s) {
            if (c == '1') {
                cur++;
                res = (res + cur) % MOD;
            } else {
                cur = 0;
            }
        }
        return static_cast<int>(res);
    }
};
